const now = new Date().toISOString();
return items.map((item) => {
  const root = item.json || {};
  const payload = root.body && typeof root.body === 'object' ? root.body : root;
  const fullName = payload.lead?.full_name || [payload.first_name, payload.last_name].filter(Boolean).join(' ').trim();
  const email = String(payload.lead?.email || payload.work_email || payload.email || '').trim().toLowerCase();
  const company = String(payload.lead?.company || payload.company_name || payload.company || '').trim();
  if (!fullName || !email || !company) throw new Error('Missing required lead fields');

  const normalized = {
    event: payload.event || 'lead.captured',
    submitted_at: payload.submitted_at || payload.capture_timestamp || now,
    cta_id: payload.cta_id || 'book-strategy-call',
    source: payload.source || 'landing_page',
    website_url: payload.website_url || null,
    primary_goal: payload.primary_goal || null,
    landing_variant: payload.landing_variant || null,
    utm_source: payload.utm_source || null,
    utm_medium: payload.utm_medium || null,
    utm_campaign: payload.utm_campaign || null,
    verification: 'unsigned_browser_form',
    lead: {
      full_name: fullName,
      email,
      company,
      team_size: payload.lead?.team_size || payload.team_size || null,
      monthly_lead_goal: payload.lead?.monthly_lead_goal ?? null,
      crm_in_use: payload.lead?.crm_in_use || payload.crm_in_use || null,
    },
  };

  normalized.crm_request = {
    arguments: {
      external_lead_id: normalized.lead.email + '-' + normalized.submitted_at,
      full_name: normalized.lead.full_name,
      email: normalized.lead.email,
      company: normalized.lead.company,
      team_size: normalized.lead.team_size,
      monthly_lead_goal: normalized.lead.monthly_lead_goal,
      crm_in_use: normalized.lead.crm_in_use,
      source: normalized.source,
      cta_id: normalized.cta_id,
      submitted_at: normalized.submitted_at,
      website_url: normalized.website_url,
      primary_goal: normalized.primary_goal,
      landing_variant: normalized.landing_variant,
      utm_source: normalized.utm_source,
      utm_medium: normalized.utm_medium,
      utm_campaign: normalized.utm_campaign,
      metadata: {
        verification: normalized.verification,
      },
    },
  };

  return { json: normalized };
});
